import{_ as t,o,c as r,ag as l,j as a,a as e}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"📚 VÝPISKY – TERAPEUTICKÉ PŘÍSTROJE","description":"","frontmatter":{},"headers":[],"relativePath":"Skola/LPT_2/Test_1.md","filePath":"Skola/LPT_2/Test_1.md"}'),n={name:"Skola/LPT_2/Test_1.md"};function s(u,i,d,h,k,c){return o(),r("div",null,[...i[0]||(i[0]=[l('<h1 id="📚-vypisky-–-terapeuticke-pristroje" tabindex="-1">📚 VÝPISKY – TERAPEUTICKÉ PŘÍSTROJE <a class="header-anchor" href="#📚-vypisky-–-terapeuticke-pristroje" aria-label="Permalink to &quot;📚 VÝPISKY – TERAPEUTICKÉ PŘÍSTROJE&quot;">​</a></h1><hr><h2 id="_1-testovani-defibrilatoru" tabindex="-1">1) Testování defibrilátorů <a class="header-anchor" href="#_1-testovani-defibrilatoru" aria-label="Permalink to &quot;1) Testování defibrilátorů&quot;">​</a></h2><h3 id="⚡-princip" tabindex="-1">⚡ Princip <a class="header-anchor" href="#⚡-princip" aria-label="Permalink to &quot;⚡ Princip&quot;">​</a></h3><ul><li>defibrilátor slouží k <strong>ukončení fibrilace komor</strong></li><li>výboj vzniká vybitím <strong>nabitého kondenzátoru</strong></li><li>cílem je <strong>depolarizovat myokard → obnovení rytmu</strong></li></ul><h3 id="📊-dulezite-hodnoty" tabindex="-1">📊 Důležité hodnoty <a class="header-anchor" href="#📊-dulezite-hodnoty" aria-label="Permalink to &quot;📊 Důležité hodnoty&quot;">​</a></h3><ul><li>energie: <ul><li>monofázický: až <strong>360 J</strong></li><li>bifázický: <strong>120–200 J</strong></li></ul></li><li>napětí: cca <strong>2–5 kV</strong></li><li>proud: desítky A</li><li>délka impulzu: <strong>5–10 ms</strong></li><li>odpor pacienta: <strong>50–100 Ω</strong></li></ul><h3 id="🔄-monofazicky-vs-bifazicky-vyboj" tabindex="-1">🔄 Monofázický vs. bifázický výboj <a class="header-anchor" href="#🔄-monofazicky-vs-bifazicky-vyboj" aria-label="Permalink to &quot;🔄 Monofázický vs. bifázický výboj&quot;">​</a></h3><ul><li><p><strong>Monofázický</strong></p><ul><li>proud teče <strong>jedním směrem</strong></li><li>vyšší energie → větší poškození tkáně</li><li>dnes se používá méně</li></ul></li><li><p><strong>Bifázický</strong></p><ul><li>proud změní směr (tam + zpět)</li><li>účinnější při nižší energii</li><li>menší poškození myokardu</li><li>dnes standard</li></ul></li></ul><h3 id="✔️-co-se-testuje" tabindex="-1">✔️ Co se testuje <a class="header-anchor" href="#✔️-co-se-testuje" aria-label="Permalink to &quot;✔️ Co se testuje&quot;">​</a></h3><ul><li>dodaná energie (J)</li><li>čas nabíjení (sekundy)</li><li>funkce synchronizace (kardioverze – R vlna)</li><li>stav baterie</li><li>elektrody (kontakt, impedance)</li></ul><h3 id="⚠️-bezpecnost" tabindex="-1">⚠️ Bezpečnost <a class="header-anchor" href="#⚠️-bezpecnost" aria-label="Permalink to &quot;⚠️ Bezpečnost&quot;">​</a></h3><ul><li>správné přiložení elektrod</li><li>testování na umělé zátěži (ne na pacientovi)</li></ul><hr><h2 id="_2-programator-kardiostimulatoru" tabindex="-1">2) Programátor kardiostimulátorů <a class="header-anchor" href="#_2-programator-kardiostimulatoru" aria-label="Permalink to &quot;2) Programátor kardiostimulátorů&quot;">​</a></h2><h3 id="⚙️-princip" tabindex="-1">⚙️ Princip <a class="header-anchor" href="#⚙️-princip" aria-label="Permalink to &quot;⚙️ Princip&quot;">​</a></h3><ul><li>zařízení pro <strong>nastavení implantovaného kardiostimulátoru</strong></li><li>komunikace probíhá <strong>telemetricky (bezdrátově)</strong></li></ul><h3 id="📊-nastavovane-parametry" tabindex="-1">📊 Nastavované parametry <a class="header-anchor" href="#📊-nastavovane-parametry" aria-label="Permalink to &quot;📊 Nastavované parametry&quot;">​</a></h3><ul><li>frekvence: <strong>30–150 imp/min (≈70)</strong></li><li>amplituda: <strong>2–10 V</strong></li><li>proud: <strong>10–60 mA</strong></li><li>šířka pulzu: <strong>≈1 ms</strong></li><li>AV zpoždění: <strong>≈120 ms</strong></li><li>refrakterní doba: <strong>≈300 ms</strong></li></ul><hr><h3 id="🧠-dalsi-parametry-z-protokolu" tabindex="-1">🧠 Další parametry (z protokolu) <a class="header-anchor" href="#🧠-dalsi-parametry-z-protokolu" aria-label="Permalink to &quot;🧠 Další parametry (z protokolu)&quot;">​</a></h3>',21),a("ul",null,[a("li",{index:"1"},[a("strong",null,"rate"),e(" → základní stimulační frekvence :contentReference[oaicite:1]")]),a("li",{index:"2"},[a("strong",null,"maximum pacing rate"),e(" → max. povolená frekvence :contentReference[oaicite:2]")]),a("li",null,[a("strong",null,"LV protection period"),a("ul",null,[a("li",{index:"3"},"ochranná doba komory po stimulaci :contentReference[oaicite:3]")])])],-1),l('<hr><h3 id="🧠-co-znamenaji-pojmy" tabindex="-1">🧠 Co znamenají pojmy <a class="header-anchor" href="#🧠-co-znamenaji-pojmy" aria-label="Permalink to &quot;🧠 Co znamenají pojmy&quot;">​</a></h3><ul><li><p><strong>AV zpoždění</strong></p><ul><li>čas mezi aktivací síní a komor</li><li>simuluje fyziologické vedení vzruchu</li></ul></li><li><p><strong>Refrakterní doba</strong></p><ul><li>období, kdy KS nereaguje na signály</li><li>zabrání falešné stimulaci</li></ul></li><li><p><strong>Citlivost</strong></p><ul><li>schopnost zachytit vlastní aktivitu srdce</li></ul></li></ul><hr><h2 id="🫀-naspe-bpeg-kod-–-prehled" tabindex="-1">🫀 NASPE/BPEG kód – přehled <a class="header-anchor" href="#🫀-naspe-bpeg-kod-–-prehled" aria-label="Permalink to &quot;🫀 NASPE/BPEG kód – přehled&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pozice</th><th>I (Chamber Paced)</th><th>II (Chamber Sensed)</th><th>III (Response to Sensing)</th><th>IV (Rate Modulation)</th><th>V (Multisite Pacing)</th></tr></thead><tbody><tr><td>Význam</td><td>Stimulovaná dutina</td><td>Snímaná dutina</td><td>Odezva na snímání</td><td>Modulace frekvence</td><td>Vícebodová stimulace</td></tr><tr><td>O</td><td>žádná</td><td>žádná</td><td>žádná</td><td>žádná</td><td>žádná</td></tr><tr><td>A</td><td>síň</td><td>síň</td><td>—</td><td>—</td><td>síň</td></tr><tr><td>V</td><td>komora</td><td>komora</td><td>—</td><td>—</td><td>komora</td></tr><tr><td>D</td><td>síň + komora</td><td>síň + komora</td><td>kombinace (I + T)</td><td>—</td><td>síň + komora</td></tr><tr><td>I</td><td>—</td><td>—</td><td>inhibice</td><td>—</td><td>—</td></tr><tr><td>T</td><td>—</td><td>—</td><td>spouštění</td><td>—</td><td>—</td></tr><tr><td>R</td><td>—</td><td>—</td><td>—</td><td>adaptace frekvence</td><td>—</td></tr></tbody></table><ul><li>Odkaz na tabulku: <a href="https://litfl.com/pacemaker-rhythms-normal-patterns/" target="_blank" rel="noreferrer">Kodove oznaceni kardiostinulátorů</a></li></ul><hr><h3 id="🧠-rychla-orientace" tabindex="-1">🧠 Rychlá orientace <a class="header-anchor" href="#🧠-rychla-orientace" aria-label="Permalink to &quot;🧠 Rychlá orientace&quot;">​</a></h3><ul><li>I = kde stimuluje</li><li>II = kde snímá</li><li>III = co udělá</li><li>IV = přizpůsobení zátěži</li><li>V = více míst stimulace</li></ul><hr><h2 id="odezva-kardiostimulatoru-naspe-bpeg-–-3-pozice" tabindex="-1">Odezva kardiostimulátoru (NASPE/BPEG – 3. pozice) <a class="header-anchor" href="#odezva-kardiostimulatoru-naspe-bpeg-–-3-pozice" aria-label="Permalink to &quot;Odezva kardiostimulátoru (NASPE/BPEG – 3. pozice)&quot;">​</a></h2><p>Udává, <strong>jak kardiostimulátor reaguje na vlastní aktivitu srdce (snímaný signál)</strong>.</p><hr><h4 id="🔹-i-–-inhibice-inhibited" tabindex="-1">🔹 I – Inhibice (Inhibited) <a class="header-anchor" href="#🔹-i-–-inhibice-inhibited" aria-label="Permalink to &quot;🔹 I – Inhibice (Inhibited)&quot;">​</a></h4><ul><li>pokud KS zachytí vlastní srdeční aktivitu → <strong>nevysílá impuls</strong></li><li>„utlumí se“</li></ul><h5 id="💡-vyznam" tabindex="-1">💡 Význam <a class="header-anchor" href="#💡-vyznam" aria-label="Permalink to &quot;💡 Význam&quot;">​</a></h5><ul><li>srdce pracuje samo → KS nezasahuje</li><li>šetří baterii</li><li>zabraňuje zbytečné stimulaci</li></ul><h5 id="📌-priklad" tabindex="-1">📌 Příklad <a class="header-anchor" href="#📌-priklad" aria-label="Permalink to &quot;📌 Příklad&quot;">​</a></h5><ul><li>pacient má vlastní rytmus → KS čeká</li><li>když rytmus vypadne → začne stimulovat</li></ul><p>👉 nejčastější režim (<strong>on demand</strong>)</p><hr><h4 id="🔹-t-–-spousteni-triggered" tabindex="-1">🔹 T – Spouštění (Triggered) <a class="header-anchor" href="#🔹-t-–-spousteni-triggered" aria-label="Permalink to &quot;🔹 T – Spouštění (Triggered)&quot;">​</a></h4><ul><li>pokud KS zachytí signál → <strong>vyšle stimulační impuls</strong></li></ul><h5 id="💡-vyznam-1" tabindex="-1">💡 Význam <a class="header-anchor" href="#💡-vyznam-1" aria-label="Permalink to &quot;💡 Význam&quot;">​</a></h5><ul><li>využívá se pro synchronizaci</li><li>KS „kopíruje“ aktivitu srdce</li></ul><h5 id="📌-priklad-1" tabindex="-1">📌 Příklad <a class="header-anchor" href="#📌-priklad-1" aria-label="Permalink to &quot;📌 Příklad&quot;">​</a></h5><ul><li>zachytí P vlnu → vyšle impuls do komory</li></ul><p>👉 méně používané</p><hr><h4 id="🔹-d-–-dualni-dual-i-t" tabindex="-1">🔹 D – Duální (Dual = I + T) <a class="header-anchor" href="#🔹-d-–-dualni-dual-i-t" aria-label="Permalink to &quot;🔹 D – Duální (Dual = I + T)&quot;">​</a></h4><ul><li>kombinuje: <ul><li><strong>inhibici</strong></li><li><strong>spouštění</strong></li></ul></li></ul><h5 id="💡-vyznam-2" tabindex="-1">💡 Význam <a class="header-anchor" href="#💡-vyznam-2" aria-label="Permalink to &quot;💡 Význam&quot;">​</a></h5><ul><li>KS se chová podle situace: <ul><li>někdy inhibuje</li><li>někdy spouští</li></ul></li></ul><h5 id="📌-priklad-2" tabindex="-1">📌 Příklad <a class="header-anchor" href="#📌-priklad-2" aria-label="Permalink to &quot;📌 Příklad&quot;">​</a></h5><ul><li>pokud je aktivita správná → neinhibuje</li><li>pokud je potřeba → synchronizuje komory</li></ul><p>👉 nejmodernější a nejpoužívanější (např. DDD režim)</p><hr><h4 id="🧠-rychle-zapamatovani" tabindex="-1">🧠 Rychlé zapamatování <a class="header-anchor" href="#🧠-rychle-zapamatovani" aria-label="Permalink to &quot;🧠 Rychlé zapamatování&quot;">​</a></h4><ul><li><strong>I = Inhibit → zastaví se</strong></li><li><strong>T = Trigger → spustí impuls</strong></li><li><strong>D = Dual → obojí</strong></li></ul><hr><h3 id="✔️-funkce" tabindex="-1">✔️ Funkce <a class="header-anchor" href="#✔️-funkce" aria-label="Permalink to &quot;✔️ Funkce&quot;">​</a></h3><ul><li>změna parametrů po implantaci</li><li>ukládání dat (počet stimulací, inhibice)</li><li>diagnostika</li></ul><hr><h2 id="_3-test-externiho-kardiostimulatoru" tabindex="-1">3) Test externího kardiostimulátoru <a class="header-anchor" href="#_3-test-externiho-kardiostimulatoru" aria-label="Permalink to &quot;3) Test externího kardiostimulátoru&quot;">​</a></h2><h3 id="⚡-princip-1" tabindex="-1">⚡ Princip <a class="header-anchor" href="#⚡-princip-1" aria-label="Permalink to &quot;⚡ Princip&quot;">​</a></h3><ul><li>generuje impulzy → <strong>vyvolá kontrakci srdce</strong></li><li>používá se při poruchách rytmu</li></ul><h3 id="📊-hodnoty" tabindex="-1">📊 Hodnoty <a class="header-anchor" href="#📊-hodnoty" aria-label="Permalink to &quot;📊 Hodnoty&quot;">​</a></h3><h4 id="📊-realne-hodnoty-z-protokolu" tabindex="-1">📊 Reálné hodnoty (z protokolu) <a class="header-anchor" href="#📊-realne-hodnoty-z-protokolu" aria-label="Permalink to &quot;📊 Reálné hodnoty (z protokolu)&quot;">​</a></h4><ul><li>amplituda: <strong>0–12 V</strong></li><li>šířka pulzu: <strong>0,05–1 ms</strong></li><li>frekvence: <strong>40–180 ppm</strong></li><li>citlivost: <strong>0,2–5 mV</strong></li></ul><h4 id="🧠-dalsi-poznatky" tabindex="-1">🧠 Další poznatky <a class="header-anchor" href="#🧠-dalsi-poznatky" aria-label="Permalink to &quot;🧠 Další poznatky&quot;">​</a></h4><ul><li>energie impulsu závisí na: <ul><li>napětí</li><li>délce pulzu</li><li>impedanci</li></ul></li><li>např.: <strong>≈63 µWs (7,5 V, 1 ms)</strong></li></ul><h4 id="⚙️-nastavitelne-prvky" tabindex="-1">⚙️ Nastavitelné prvky <a class="header-anchor" href="#⚙️-nastavitelne-prvky" aria-label="Permalink to &quot;⚙️ Nastavitelné prvky&quot;">​</a></h4><ul><li>amplituda</li><li>frekvence (ppm)</li><li>šířka pulzu</li><li>citlivost</li><li>overdrive frekvence</li></ul><h4 id="neprima-stimulace-transkutanni" tabindex="-1">Nepřímá stimulace (transkutánní) <a class="header-anchor" href="#neprima-stimulace-transkutanni" aria-label="Permalink to &quot;Nepřímá stimulace (transkutánní)&quot;">​</a></h4><ul><li>napětí: <strong>50–300 V</strong></li><li>proud: <strong>50–300 mA</strong></li><li>nevýhoda: bolest, stimulace svalů</li></ul><h4 id="prima-stimulace-endokardialni" tabindex="-1">Přímá stimulace (endokardiální) <a class="header-anchor" href="#prima-stimulace-endokardialni" aria-label="Permalink to &quot;Přímá stimulace (endokardiální)&quot;">​</a></h4><ul><li>proud: <strong>10–60 mA</strong></li><li>frekvence: <strong>30–150 imp/min</strong></li><li>šířka pulzu: <strong>≈1 ms</strong></li></ul><h3 id="🧠-typy-stimulace" tabindex="-1">🧠 Typy stimulace <a class="header-anchor" href="#🧠-typy-stimulace" aria-label="Permalink to &quot;🧠 Typy stimulace&quot;">​</a></h3><ul><li><p><strong>neřízená</strong></p><ul><li>pevná frekvence (~70/min)</li><li>nezohledňuje vlastní rytmus</li></ul></li><li><p><strong>řízená („on demand“)</strong></p><ul><li>reaguje na aktivitu srdce</li><li>stimuluje jen když je potřeba</li></ul></li></ul><h3 id="✔️-co-se-testuje-1" tabindex="-1">✔️ Co se testuje <a class="header-anchor" href="#✔️-co-se-testuje-1" aria-label="Permalink to &quot;✔️ Co se testuje&quot;">​</a></h3><ul><li>amplituda impulzů</li><li>frekvence</li><li>stabilita signálu</li><li>správná reakce na EKG (inhibice)</li><li>tzv. <strong>capture</strong> (zda impuls vyvolá kontrakci)</li></ul><hr><h2 id="_4-elektrokoagulace" tabindex="-1">4) Elektrokoagulace <a class="header-anchor" href="#_4-elektrokoagulace" aria-label="Permalink to &quot;4) Elektrokoagulace&quot;">​</a></h2><h3 id="⚡-princip-2" tabindex="-1">⚡ Princip <a class="header-anchor" href="#⚡-princip-2" aria-label="Permalink to &quot;⚡ Princip&quot;">​</a></h3><ul><li>vysokofrekvenční proud → <strong>zahřívá tkáň</strong></li><li>dochází ke <strong>koagulaci bílkovin → zástava krvácení</strong></li></ul><h3 id="📊-hodnoty-1" tabindex="-1">📊 Hodnoty <a class="header-anchor" href="#📊-hodnoty-1" aria-label="Permalink to &quot;📊 Hodnoty&quot;">​</a></h3><ul><li>frekvence: <strong>stovky kHz – MHz</strong></li><li>výkon: jednotky až stovky W</li><li>teplota: <ul><li>koagulace: <strong>60–100 °C</strong></li></ul></li></ul><hr><h3 id="⚡-rezimy-elektrokoagulace" tabindex="-1">⚡ Režimy elektrokoagulace <a class="header-anchor" href="#⚡-rezimy-elektrokoagulace" aria-label="Permalink to &quot;⚡ Režimy elektrokoagulace&quot;">​</a></h3><hr><h4 id="_1-rezaci-rezim-cut" tabindex="-1">1) Řezací režim (CUT) <a class="header-anchor" href="#_1-rezaci-rezim-cut" aria-label="Permalink to &quot;1) Řezací režim (CUT)&quot;">​</a></h4><ul><li><strong>kontinuální vysokofrekvenční signál (sinusový průběh)</strong></li><li>vysoká hustota energie</li><li>→ tkáň se <strong>odpaří (vaporizace buněk)</strong></li></ul><h5 id="charakteristika" tabindex="-1">Charakteristika <a class="header-anchor" href="#charakteristika" aria-label="Permalink to &quot;Charakteristika&quot;">​</a></h5><ul><li>hladký, čistý řez</li><li>minimální koagulace okrajů</li><li>větší krvácení</li><li>dochází k <strong>explozi buněk vlivem odpaření intracelulární tekutiny</strong></li></ul><h5 id="📊-hodnoty-2" tabindex="-1">📊 Hodnoty <a class="header-anchor" href="#📊-hodnoty-2" aria-label="Permalink to &quot;📊 Hodnoty&quot;">​</a></h5><ul><li>napětí: <strong>stovky V</strong></li><li>proud: <strong>stovky mA až jednotky A</strong></li></ul><hr><h4 id="_2-koagulacni-rezim-coag" tabindex="-1">2) Koagulační režim (COAG) <a class="header-anchor" href="#_2-koagulacni-rezim-coag" aria-label="Permalink to &quot;2) Koagulační režim (COAG)&quot;">​</a></h4><ul><li><strong>přerušovaný (pulzní) signál s pauzami</strong></li><li>vyšší špičkové napětí</li><li>→ tkáň se <strong>zahřívá → koagulace bílkovin</strong></li></ul><h5 id="charakteristika-1" tabindex="-1">Charakteristika <a class="header-anchor" href="#charakteristika-1" aria-label="Permalink to &quot;Charakteristika&quot;">​</a></h5><ul><li>zástava krvácení</li><li>menší řezný efekt</li><li>vznik „spálené“ tkáně</li><li>uzavření cév</li></ul><h5 id="📊-hodnoty-3" tabindex="-1">📊 Hodnoty <a class="header-anchor" href="#📊-hodnoty-3" aria-label="Permalink to &quot;📊 Hodnoty&quot;">​</a></h5><ul><li>napětí: až <strong>několik kV (např. až ~9000 V)</strong></li><li>proud: <strong>stovky mA – jednotky A</strong></li></ul><hr><h4 id="_3-smiseny-rezim-blend" tabindex="-1">3) Smíšený režim (BLEND) <a class="header-anchor" href="#_3-smiseny-rezim-blend" aria-label="Permalink to &quot;3) Smíšený režim (BLEND)&quot;">​</a></h4><ul><li>kombinace <strong>CUT + COAG</strong></li><li>signál obsahuje jak kontinuální, tak pulzní složku</li></ul><h5 id="charakteristika-2" tabindex="-1">Charakteristika <a class="header-anchor" href="#charakteristika-2" aria-label="Permalink to &quot;Charakteristika&quot;">​</a></h5><ul><li>současně řeže i koaguluje</li><li>kompromis: <ul><li>menší krvácení než CUT</li><li>lepší řez než COAG</li></ul></li></ul><hr><h3 id="🧠-signalove-rozdily-dulezite" tabindex="-1">🧠 Signálové rozdíly (DŮLEŽITÉ!) <a class="header-anchor" href="#🧠-signalove-rozdily-dulezite" aria-label="Permalink to &quot;🧠 Signálové rozdíly (DŮLEŽITÉ!)&quot;">​</a></h3><ul><li><p><strong>CUT</strong></p><ul><li>kontinuální sinus</li><li>bez přerušení</li></ul></li><li><p><strong>COAG</strong></p><ul><li>krátké impulzy + pauzy</li><li>vysoké špičky (crest faktor ↑)</li></ul></li><li><p><strong>BLEND</strong></p><ul><li><p>kombinace obou průběhů</p></li><li><p>přesně viditelné na osciloskopu</p></li></ul></li></ul><hr><h3 id="📊-vykony-a-proudy-z-mereni" tabindex="-1">📊 Výkony a proudy (z měření) <a class="header-anchor" href="#📊-vykony-a-proudy-z-mereni" aria-label="Permalink to &quot;📊 Výkony a proudy (z měření)&quot;">​</a></h3><h5 id="vykon-priblizne" tabindex="-1">Výkon (přibližně) <a class="header-anchor" href="#vykon-priblizne" aria-label="Permalink to &quot;Výkon (přibližně)&quot;">​</a></h5><ul><li>CUT: až <strong>~39 W</strong></li><li>BLEND: až <strong>~25 W</strong></li><li>COAG: až <strong>~17 W</strong></li></ul><p>👉 CUT má nejvyšší výkon → proto řeže</p><hr><h4 id="⚡-dalsi-rozdeleni" tabindex="-1">⚡ Další rozdělení <a class="header-anchor" href="#⚡-dalsi-rozdeleni" aria-label="Permalink to &quot;⚡ Další rozdělení&quot;">​</a></h4><h5 id="🔹-monopolarni-rezim" tabindex="-1">🔹 Monopolární režim <a class="header-anchor" href="#🔹-monopolarni-rezim" aria-label="Permalink to &quot;🔹 Monopolární režim&quot;">​</a></h5><ul><li>proud: <strong>aktivní elektroda → pacient → návratová elektroda</strong></li><li>větší rozsah účinku</li><li>nutná kontrola kontaktu elektrody</li></ul><h6 id="🔹-bipolarni-rezim" tabindex="-1">🔹 Bipolární režim <a class="header-anchor" href="#🔹-bipolarni-rezim" aria-label="Permalink to &quot;🔹 Bipolární režim&quot;">​</a></h6><ul><li>proud mezi dvěma hroty</li><li>přesnější, bezpečnější</li><li>menší riziko popálení</li></ul><hr><h4 id="🧠-dulezity-pojem" tabindex="-1">🧠 Důležitý pojem <a class="header-anchor" href="#🧠-dulezity-pojem" aria-label="Permalink to &quot;🧠 Důležitý pojem&quot;">​</a></h4><h5 id="crest-faktor" tabindex="-1">Crest faktor <a class="header-anchor" href="#crest-faktor" aria-label="Permalink to &quot;Crest faktor&quot;">​</a></h5><ul><li>poměr: <strong>V_peak / V_RMS</strong></li><li>určuje „špičatost“ signálu</li><li>COAG má vyšší crest faktor → větší špičky</li></ul><hr><h3 id="⚠️-shrnuti-na-test" tabindex="-1">⚠️ Shrnutí na test <a class="header-anchor" href="#⚠️-shrnuti-na-test" aria-label="Permalink to &quot;⚠️ Shrnutí na test&quot;">​</a></h3><ul><li><strong>CUT → kontinuální sinus → řeže (vaporizace buněk)</strong></li><li><strong>COAG → pulzní → koaguluje (zástava krvácení)</strong></li><li><strong>BLEND → kombinace</strong></li><li>COAG má <strong>vyšší napětí (až kV)</strong></li><li>CUT má <strong>vyšší výkon → řez</strong></li></ul><hr><h3 id="⚠️-bezpecnost-1" tabindex="-1">⚠️ Bezpečnost <a class="header-anchor" href="#⚠️-bezpecnost-1" aria-label="Permalink to &quot;⚠️ Bezpečnost&quot;">​</a></h3><ul><li>kontrola přechodového odporu elektrody</li><li>špatný kontakt → riziko popálení</li></ul><hr><h2 id="_5-laser" tabindex="-1">5) Laser <a class="header-anchor" href="#_5-laser" aria-label="Permalink to &quot;5) Laser&quot;">​</a></h2><h3 id="⚡-princip-3" tabindex="-1">⚡ Princip <a class="header-anchor" href="#⚡-princip-3" aria-label="Permalink to &quot;⚡ Princip&quot;">​</a></h3><ul><li>LASER = <strong>zesílení záření stimulovanou emisí</strong></li><li>zdroj <strong>koherentního, monochromatického světla</strong></li></ul><h3 id="📊-vlastnosti" tabindex="-1">📊 Vlastnosti <a class="header-anchor" href="#📊-vlastnosti" aria-label="Permalink to &quot;📊 Vlastnosti&quot;">​</a></h3><ul><li>vysoká energie</li><li>malá rozbíhavost</li><li>velká pronikavost</li><li>účinnost (polovodičové): až <strong>~50 %</strong></li></ul><h3 id="🧠-dulezite-pojmy" tabindex="-1">🧠 Důležité pojmy <a class="header-anchor" href="#🧠-dulezite-pojmy" aria-label="Permalink to &quot;🧠 Důležité pojmy&quot;">​</a></h3><ul><li><p><strong>Koherence</strong></p><ul><li>všechny vlny mají stejnou fázi</li></ul></li><li><p><strong>Monochromatičnost</strong></p><ul><li>jedno vlnové délky (barva)</li></ul></li><li><p><strong>Kolimace</strong></p><ul><li>paprsek se téměř nerozbíhá</li></ul></li></ul><h3 id="💉-vyuziti" tabindex="-1">💉 Využití <a class="header-anchor" href="#💉-vyuziti" aria-label="Permalink to &quot;💉 Využití&quot;">​</a></h3><ul><li>chirurgie (řezání, koagulace)</li><li>oftalmologie (sítnice, čočka)</li><li>dermatologie</li><li>rehabilitace (ohřev tkání)</li></ul><h3 id="⚠️-rizika" tabindex="-1">⚠️ Rizika <a class="header-anchor" href="#⚠️-rizika" aria-label="Permalink to &quot;⚠️ Rizika&quot;">​</a></h3><ul><li>poškození sítnice</li><li>nutnost ochranných brýlí</li></ul><hr><h1 id="🧠-rychle-shrnuti-na-test" tabindex="-1">🧠 RYCHLÉ SHRNUTÍ NA TEST <a class="header-anchor" href="#🧠-rychle-shrnuti-na-test" aria-label="Permalink to &quot;🧠 RYCHLÉ SHRNUTÍ NA TEST&quot;">​</a></h1><ul><li>defibrilátor → <strong>energie (J), bifázický vs. monofázický</strong></li><li>kardiostimulátor → <strong>frekvence, mA, ms</strong></li><li>elektrokoagulace → <strong>teplota + typy</strong></li><li>laser → <strong>koherence + využití</strong></li></ul>',128)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
